(function() {'use strict';
class StateManager{static _instance=null;constructor(){if(StateManager._instance)return StateManager._instance;this.state={currentPage:'upload',books:[],selectedBookId:null,currentFile:null,processingStatus:{fileUpload:{status:'pending',progress:0},textPreprocess:{status:'pending',progress:0},chapterOutline:{status:'pending',progress:0},coarseOutline:{status:'pending',progress:0},mainOutline:{status:'pending',progress:0},worldOutline:{status:'pending',progress:0}},errors:[],settings:{}};this.listeners=new Map();StateManager._instance=this;}static getInstance(){return StateManager._instance||new StateManager();}get(path){if(!path)return{...this.state};const keys=path.split('.');let value=this.state;for(const key of keys){if(value===undefined)return undefined;value=value[key];}return value;}set(path,value){const keys=path.split('.');const lastKey=keys.pop();let target=this.state;for(const key of keys){if(!(key in target))target[key]={};target=target[key];}target[lastKey]=value;this.notify(path);}delete(path){const keys=path.split('.');const lastKey=keys.pop();let target=this.state;for(const key of keys){if(!(key in target))return false;target=target[key];}if(target&&lastKey in target){delete target[lastKey];this.notify(path);return true;}return false;}subscribe(path,callback){const id=Date.now()+Math.random();if(!this.listeners.has(path))this.listeners.set(path,new Map());this.listeners.get(path).set(id,callback);return id;}notify(path){if(this.listeners.has(path)){const value=this.get(path);this.listeners.get(path).forEach(cb=>{try{cb(value);}catch(e){console.error(e);}});}}}
class APIClient{constructor(config={}){this.baseUrl=config.baseUrl||'/api/v1';this.mockMode=config.mockMode!==false;this.listeners=new Map();}async request(method,endpoint,data){if(this.mockMode)return this.mockRequest(method,endpoint,data);const url=`${this.baseUrl}${endpoint}`;const response=await fetch(url,{method,headers:{'Content-Type':'application/json'},body:data?JSON.stringify(data):null});if(!response.ok)throw new Error(`HTTP ${response.status}`);return response.json();}async mockRequest(method,endpoint,data){await new Promise(r=>setTimeout(r,300));if(endpoint==='/books')return this.mockGetBooks();if(endpoint.startsWith('/books/')){const bookId=endpoint.split('/')[2];if(endpoint.endsWith('/tree'))return this.mockGetOutlineTree(bookId);return this.mockGetBook(bookId);}throw new Error(`Unknown endpoint: ${endpoint}`);}async uploadBook(file,info){await new Promise(r=>setTimeout(r,1000));const bookId='book_'+Date.now();setTimeout(()=>this.startMockProcessing({bookId}),500);return{success:true,bookId,message:'上传成功'};}startMockProcessing(task){const stages=['fileUpload','textPreprocess','chapterOutline','coarseOutline','mainOutline','worldOutline'];let idx=0,progress=0;const interval=setInterval(()=>{if(idx>=stages.length){clearInterval(interval);this.emit('completed',{bookId:task.bookId});return;}const stage=stages[idx];progress+=20;this.emit('progress',{stage,progress});if(progress>=100){progress=0;idx++;}},500);}mockGetBooks(){return{success:true,books:[{bookId:'book_1',title:'示例小说',status:'COMPLETED'}]};}mockGetBook(id){return{success:true,book:{bookId:id,title:'示例小说'}};}mockGetOutlineTree(id){return{success:true,tree:{outlineId:'world_1',outlineType:'WORLD',label:'世界纲',children:[]}};}on(event,cb){if(!this.listeners.has(event))this.listeners.set(event,[]);this.listeners.get(event).push(cb);}emit(event,data){if(this.listeners.has(event))this.listeners.get(event).forEach(cb=>cb(data));}}
class ToastManager{constructor(){let container=document.getElementById('toast-container');if(!container){container=document.createElement('div');container.id='toast-container';container.className='toast-container';document.body.appendChild(container);}this.container=container;}show(msg,type='info',duration=3000){const toast=document.createElement('div');toast.className=`toast ${type}`;toast.textContent=msg;this.container.appendChild(toast);setTimeout(()=>{toast.style.animation='slideOut 0.3s ease forwards';setTimeout(()=>toast.remove(),300);},duration);}success(msg){this.show(msg,'success');}error(msg){this.show(msg,'error');}warning(msg){this.show(msg,'warning');}info(msg){this.show(msg,'info');}}
class NovelPlatformApp{constructor(){this.state=StateManager.getInstance();this.api=null;this.uploader=null;this.progressMonitor=null;this.toastManager=null;}async init(){console.log('[App] 初始化AI小说拆书系统...');try{this.toastManager=new ToastManager();window.toastManager=this.toastManager;this.toastManager.info('系统初始化中...');const settings=this.state.get('settings')||{};this.api=new APIClient({baseUrl:settings.apiBaseUrl||'http://localhost:8000/api/v1',mockMode:settings.mockMode!==false});this.api.on('progress',data=>{this.state.set(`processingStatus.${data.stage}`,{status:'active',progress:data.progress});if(this.progressMonitor)this.progressMonitor.update(this.state.get('processingStatus'));});this.api.on('completed',result=>{this.toastManager.success('处理完成！');this.state.set('processingStatus.isProcessing',false);});this.initComponents();this.bindEvents();this.loadSettings();console.log('[App] 初始化完成');this.toastManager.success('系统就绪');}catch(error){console.error('[App] 初始化失败:',error);this.toastManager?.error('初始化失败: '+error.message);}}initComponents(){const uploaderContainer=document.getElementById('fileUploader');if(uploaderContainer)this.uploader=this.createUploader(uploaderContainer);const progressContainer=document.getElementById('progressMonitor');if(progressContainer)this.progressMonitor=this.createProgressMonitor(progressContainer);}createUploader(container){const formats=['.epub','.txt','.doc','.docx','.pdf'];container.innerHTML='<div class="upload-zone" id="uploadZone"><div class="upload-icon"><svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5" width="48" height="48"><path stroke-linecap="round" stroke-linejoin="round" d="M12 16.5V9.75m0 0l3 3m-3-3l-3 3M6.75 19.5a4.5 4.5 0 01-1.41-8.775 5.25 5.25 0 0110.233-2.33 3 3 0 013.758 3.848A3.75 3.752 0 0118 19.5H6.75z"/></svg></div><p class="upload-text">拖拽文件到此处，或点击选择文件</p><p class="upload-hint">支持上传小说文件</p><div class="upload-formats">'+formats.map(f=>'<span class="format-badge">'+f+'</span>').join('')+'</div><input type="file" class="file-input" id="fileInput" accept="'+formats.join(',')+'"></div>';const zone=container.querySelector('#uploadZone');const fileInput=container.querySelector('#fileInput');const app=this;zone.addEventListener('click',()=>fileInput.click());fileInput.addEventListener('change',e=>{if(e.target.files.length>0)app.handleFileSelect(e.target.files[0]);});zone.addEventListener('dragover',e=>{e.preventDefault();zone.classList.add('drag-over');});zone.addEventListener('dragleave',e=>{e.preventDefault();zone.classList.remove('drag-over');});zone.addEventListener('drop',e=>{e.preventDefault();zone.classList.remove('drag-over');if(e.dataTransfer.files.length>0)app.handleFileSelect(e.dataTransfer.files[0]);});return{reset:()=>{fileInput.value='';zone.classList.remove('hidden');}};}createProgressMonitor(container){const stages=['fileUpload','textPreprocess','chapterOutline','coarseOutline','mainOutline','worldOutline'];const names=['文件上传','文本预处理','章纲提取','粗纲生成','大纲生成','世界纲生成'];const state={};stages.forEach(id=>state[id]={status:'pending',progress:0});container.innerHTML='<div class="card"><div class="card-header"><h3 class="card-title">处理进度</h3></div><div class="card-body"><div class="processing-status">'+stages.map((id,i)=>'<div class="status-item" data-stage="'+id+'"><div class="status-icon pending"></div><div class="status-content"><div class="status-title">'+names[i]+'</div><div class="status-progress">等待中</div></div></div>').join('')+'</div></div></div>';return{update(status={}){stages.forEach(id=>{if(status[id]){Object.assign(state[id],status[id]);const el=container.querySelector('[data-stage="'+id+'"]');if(el){const s=state[id];el.querySelector('.status-icon').className='status-icon '+s.status;el.querySelector('.status-progress').textContent=s.status==='completed'?'完成':s.status==='error'?'失败':s.status==='active'?Math.round(s.progress)+'%':'等待中';}}});}};}bindEvents(){document.querySelectorAll('.nav-link').forEach(link=>{link.addEventListener('click',e=>{e.preventDefault();this.navigateTo(link.dataset.page);});});document.getElementById('btnStartProcess')?.addEventListener('click',()=>this.handleStartProcess());document.getElementById('btnReset')?.addEventListener('click',()=>this.handleReset());document.getElementById('btnBackToLibrary')?.addEventListener('click',()=>this.navigateTo('library'));document.getElementById('themeToggle')?.addEventListener('click',()=>this.toggleTheme());document.getElementById('btnSaveSettings')?.addEventListener('click',()=>this.saveSettings());document.getElementById('btnResetSettings')?.addEventListener('click',()=>this.resetSettings());const tempSlider=document.getElementById('temperature');const tempValue=document.getElementById('temperatureValue');if(tempSlider&&tempValue)tempSlider.addEventListener('input',()=>tempValue.textContent=tempSlider.value);document.querySelectorAll('.tab-btn').forEach(btn=>{btn.addEventListener('click',()=>{const tabId=btn.dataset.tab;btn.closest('.outline-container')?.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));btn.classList.add('active');btn.closest('.outline-container')?.querySelectorAll('.tab-content').forEach(c=>c.classList.remove('active'));document.getElementById('tab-'+tabId)?.classList.add('active');});});}handleFileSelect(file){const fileName=file.name.replace(/\.[^/.]+$/,'');const titleInput=document.getElementById('bookTitle');if(titleInput)titleInput.value=fileName;document.getElementById('bookInfoForm')?.classList.remove('hidden');this.state.set('currentFile',{file,name:file.name,size:file.size,type:file.type});this.toastManager.success('已选择文件: '+file.name);}async handleStartProcess(){const file=this.state.get('currentFile');if(!file){this.toastManager.warning('请先选择文件');return;}const bookInfo={title:document.getElementById('bookTitle')?.value||file.name,author:document.getElementById('bookAuthor')?.value||'未知'};this.state.set('processingStatus',{isProcessing:true,fileUpload:{status:'active',progress:0},textPreprocess:{status:'pending',progress:0},chapterOutline:{status:'pending',progress:0},coarseOutline:{status:'pending',progress:0},mainOutline:{status:'pending',progress:0},worldOutline:{status:'pending',progress:0}});document.getElementById('progressSection')?.classList.remove('hidden');const btn=document.getElementById('btnStartProcess');if(btn){btn.disabled=true;btn.innerHTML='处理中...';}try{await this.api.uploadBook(file.file,bookInfo);}catch(error){console.error('[App] 处理失败:',error);this.toastManager.error('处理失败: '+error.message);}finally{if(btn){btn.disabled=false;btn.innerHTML='开始处理';}}}handleReset(){if(this.uploader)this.uploader.reset();document.getElementById('bookInfoForm')?.classList.add('hidden');document.getElementById('progressSection')?.classList.add('hidden');document.getElementById('bookTitle').value='';document.getElementById('bookAuthor').value='';document.getElementById('bookDescription').value='';this.state.delete('currentFile');this.toastManager.info('已重置');}navigateTo(page){document.querySelectorAll('.nav-link').forEach(l=>l.classList.toggle('active',l.dataset.page===page));document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));const targetPage=document.getElementById('page-'+page);if(targetPage){targetPage.classList.add('active');this.currentPage=page;}console.log('[App] 导航到:',page);}toggleTheme(){document.body.classList.toggle('dark-theme');const isDark=document.body.classList.contains('dark-theme');this.state.set('settings.darkTheme',isDark);this.toastManager.info(isDark?'已切换到暗色主题':'已切换到亮色主题');}loadSettings(){try{const saved=localStorage.getItem('novel-platform-settings');if(saved){const settings=JSON.parse(saved);this.state.set('settings',{...this.state.get('settings'),...settings});const el=id=>document.getElementById(id);if(el('apiBaseUrl'))el('apiBaseUrl').value=settings.apiBaseUrl||'';if(el('apiKey'))el('apiKey').value=settings.apiKey||'';if(el('modelName'))el('modelName').value=settings.modelName||'gpt-5.4-nano';if(el('temperature'))el('temperature').value=settings.temperature||0.7;if(el('temperatureValue'))el('temperatureValue').textContent=settings.temperature||0.7;if(el('maxTokens'))el('maxTokens').value=settings.maxTokens||4096;if(el('chapterSize'))el('chapterSize').value=settings.chapterSize||2000;if(el('mockMode'))el('mockMode').checked=settings.mockMode!==false;if(settings.darkTheme)document.body.classList.add('dark-theme');}}catch(e){console.error('[App] 加载设置失败:',e);}}saveSettings(){try{const settings={apiBaseUrl:document.getElementById('apiBaseUrl')?.value||'',apiKey:document.getElementById('apiKey')?.value||'',modelName:document.getElementById('modelName')?.value||'gpt-5.4-nano',temperature:parseFloat(document.getElementById('temperature')?.value||0.7),maxTokens:parseInt(document.getElementById('maxTokens')?.value||4096),chapterSize:parseInt(document.getElementById('chapterSize')?.value||2000),mockMode:document.getElementById('mockMode')?.checked!==false,darkTheme:document.body.classList.contains('dark-theme')};localStorage.setItem('novel-platform-settings',JSON.stringify(settings));this.state.set('settings',settings);this.toastManager.success('设置已保存');}catch(e){this.toastManager.error('保存失败');}}resetSettings(){localStorage.removeItem('novel-platform-settings');this.state.set('settings',{});this.loadSettings();this.toastManager.info('设置已重置');}}
document.addEventListener('DOMContentLoaded',function(){console.log('[Bundle] AI小说拆书系统启动...');window.app=new NovelPlatformApp();window.app.init().catch(error=>{console.error('[Bundle] 应用初始化失败:',error);const errorDiv=document.createElement('div');errorDiv.style.cssText='position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);background:#ef4444;color:white;padding:20px;border-radius:8px;max-width:80%;text-align:center;z-index:9999;font-family:sans-serif;';errorDiv.innerHTML='<h3 style="margin:0 0 10px;">初始化失败</h3><p style="margin:0;">'+error.message+'</p><button onclick="location.reload()" style="margin-top:15px;padding:8px 16px;border:none;border-radius:4px;background:white;color:#ef4444;cursor:pointer;">刷新重试</button>';document.body.appendChild(errorDiv);});});
window.StateManager=StateManager;window.APIClient=APIClient;window.ToastManager=ToastManager;window.NovelPlatformApp=NovelPlatformApp;
console.log('[Bundle] 脚本模块加载完成');
})();